#!/usr/bin/env python3
"""
Aplica:
  1) Imagen de fondo (azul oscuro + circulos difuminados) en tema oscuro
     para dashboard, superadmin, login y portal publico.
  2) Oculta el boton de sol/luna en /p/[slug]/cita/[id].
  3) La seccion 'Opiniones de clientes' del portal ahora siempre se
     muestra (con estado vacio si no hay reseñas todavia).

Ejecutar desde la raiz del repo (carpeta que contiene 'src' y 'public'):
    python3 apply_dark_bg_and_fixes.py
"""

import base64
from pathlib import Path

FILES = {
    'public/images/dark-bg.svg': """""",
    'src/components/ThemeSwitch.tsx': """""",
    'src/components/PortalClient.tsx': """""",
    'src/components/dashboard.css': """""",
    'src/components/superadmin.css': """""",
    'src/components/auth.css': """""",
    'src/components/portal.css': """""",
}

def main():
    for relpath, b64 in FILES.items():
        p = Path(relpath)
        p.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64)
        p.write_bytes(content)
        print(f"escrito: {relpath} ({len(content)} bytes)")
    print()
    print("Listo. Luego:")
    print("  git add -A")
    print("  git commit -m 'Fondo oscuro con circulos difuminados, ocultar toggle en cita-manage, reseñas siempre visibles'")
    print("  git push")

if __name__ == "__main__":
    main()